float or_(float a, float b) {
  return float( bool(a) || bool(b) );
}
vec4 or_(vec4 v1, vec4 v2) {
  bvec4 b1 = bvec4(v1);
  bvec4 b2 = bvec4(v2);
  return vec4( b1.r || b2.r ,
              b1.g || b2.g,
              b1.b || b2.b,
              b1.a || b2.a );
}

